'use strict';document.addEventListener('DOMContentLoaded',function(){const e=document.body.getAttribute('data-ip');if(e){const t=document.createElement('div');t.className='ip-address',t.textContent='Your IP address: '+e;const n=document.getElementById('ip-address-placeholder');n&&n.appendChild(t)}else console.warn('IP address not found on the page.');const o=document.querySelectorAll('.bat');o.forEach(function(e){e.style.opacity='0',e.offsetHeight,e.style.opacity='1',e.style.animationPlayState='running'})});